    using reaction::ObserverNode;

    // 1. Create observer nodes (target + observer)
    auto target   = std::make_shared<TestObserverClosure>(nodeName + "_target");
    auto observer = std::make_shared<TestObserverClosure>(nodeName + "_observer");

    // 2. Get observer graph instance
    auto& graph = ObserverGraph::getInstance();

    // 3. Add observer relationship: target -> observer
    graph.addObserver(target, observer);

    // 4. Notify target and verify observer was notified
    target->valueChanged(true);

    bool firstPhaseOk = observer->wasChanged() && observer->getCallCount() == 1;

    // 5. Reset observer state
    // (we can't modify internal members directly, so we re-create the observer
    //  node and reattach it, but that would defeat the purpose. Instead,
    //  we keep the same node and use additional notifications to check
    //  post-closure behavior via callCount.)
    // Here we interpret "reset observer state" as logical verification
    // based on the call count before and after closure, so no mutation.

    int callCountBeforeClose = observer->getCallCount();

    // 6. Close observer node (remove it from the graph)
    graph.closeNode(observer);

    // 7. Notify target again
    target->valueChanged(true);

    // 8. Verify observer was not notified after closure
    int callCountAfterClose = observer->getCallCount();
    bool secondPhaseOk = (callCountAfterClose == callCountBeforeClose);

    // 9. Return success status
    return firstPhaseOk && secondPhaseOk;
}

