namespace test_reaction {

// ============================================
// Data model definitions
// ============================================

class TestTransactionalObserver : public reaction::ObserverNode {
public:
    TestTransactionalObserver(const std::string& name) : m_name(name), m_changed(false) {}

    void valueChanged(bool changed = true) override {
        m_changed = changed;
        m_callCount++;
        // Call base class to propagate notification to observers
        ObserverNode::valueChanged(changed);
    }

    bool wasChanged() const { return m_changed; }
    int getCallCount() const { return m_callCount; }
    const std::string& getName() const { return m_name; }

    void reset() {
        m_changed = false;
        m_callCount = 0;
    }

private:
    std::string m_name;
    bool m_changed;
    int m_callCount = 0;
};

// ============================================
// Function implementations
// ============================================

/**
 * Function: Test transactional observer updates
 *
 * Steps:
 * 1. Create observer nodes (source, intermediate, target)
 * 2. Get observer graph instance
 * 3. Set up initial relationship: source -> intermediate -> target
 * 4. Notify source and verify relationship works
 * 5. Reset observer for next test
 * 6. Attempt transactional update that would create cycle
 *    (trying to add edge target -> source)
 * 7. Catch cycle exception if thrown
 * 8. Notify source again
 * 9. Verify original relationship is preserved (target still updates, no extra edges)
 * 10. Return success status
 *
 * @param nodeName Name for the source node (for identification only)
 * @return bool Whether transactional update behaved correctly
 *              (cycle prevented and original graph preserved)
 */
bool test_transactional_update(const std::string& nodeName) {
    using reaction::ObserverGraph;
    using reaction::ObserverNode;

    // 1. Create observer nodes
    auto source = std::make_shared<TestTransactionalObserver>(nodeName);
    auto intermediate = std::make_shared<TestTransactionalObserver>(nodeName + "_mid");
    auto target = std::make_shared<TestTransactionalObserver>(nodeName + "_target");

    // 2. Get observer graph instance
    auto& graph = ObserverGraph::getInstance();

    // 3. Set up initial relationship: source -> intermediate -> target
    graph.addObserver(source, intermediate);
    graph.addObserver(intermediate, target);

    // 4. Notify source and verify relationship works
    source->valueChanged(true);

    bool initialOk = intermediate->wasChanged() &&
                     target->wasChanged() &&
                     intermediate->getCallCount() == 1 &&
                     target->getCallCount() == 1;

    if (!initialOk) {
        return false;
    }

    // 5. Reset observers for next test
    source->reset();
    intermediate->reset();
    target->reset();

    bool cyclePrevented = true;

    // 6. Attempt transactional update that would create cycle: target -> source
    try {
        // The transactional API is driven via the node:
        // this will internally call ObserverGraph::updateObserversTransactional(...)
        // and we attempt to add a back-edge that would introduce a cycle.
        target->updateObservers([&](ObserverNode::NodePtr&) {
            // Add an observer that creates a cycle: source observes target,
            // while target already (indirectly) observes source.
            graph.addObserver(target, source);
        });
        // If no exception is thrown, cycle detection failed
        cyclePrevented = false;
    } catch (...) {
        // 7. Catch cycle exception if thrown
        cyclePrevented = true;
    }

    // 8. Notify source again
    source->valueChanged(true);

    // 9. Verify original relationship is preserved
    bool relationshipPreserved =
        intermediate->wasChanged() &&
        target->wasChanged() &&
        intermediate->getCallCount() == 1 &&
        target->getCallCount() == 1;

    // Also require that the cycle was prevented
    return cyclePrevented && relationshipPreserved;
}

}  // namespace test_reaction
