/**
 * Function: Test chained observer relationships
 *
 * @param targetName Name for the target node
 * @param observer1Name Name for the first observer node
 * @param observer2Name Name for the second observer node (observes observer1)
 * @return std::pair<int, bool> Pair of total call count and whether chain notification worked correctly
 */
std::pair<int, bool> test_chained_observers(const std::string& targetName, 
                                            const std::string& observer1Name, 
                                            const std::string& observer2Name) {
    using reaction::ObserverGraph;
    using reaction::ObserverNode;

    // 1. Create observer nodes
    auto target    = std::make_shared<TestChainedObserver>(targetName);
    auto observer1 = std::make_shared<TestChainedObserver>(observer1Name);
    auto observer2 = std::make_shared<TestChainedObserver>(observer2Name);

    // 2. Get observer graph instance
    auto &graph = ObserverGraph::getInstance();

    // 3. Set up chain relationships:
    //    target -> observer1 -> observer2
    graph.addObserver(target, observer1);
    graph.addObserver(observer1, observer2);

    // Ensure clean initial state
    target->reset();
    observer1->reset();
    observer2->reset();

    // 4. Notify target
    target->valueChanged(true);

    // 5. Verify both observers were notified
    const bool targetNotified    = target->wasChanged();
    const bool observer1Notified = observer1->wasChanged();
    const bool observer2Notified = observer2->wasChanged();

    // 6. Calculate total call count
    const int totalCallCount =
        target->getCallCount() +
        observer1->getCallCount() +
        observer2->getCallCount();

    // Chain notification is correct if:
    // - target, observer1, and observer2 were all marked changed
    // - each was called exactly once in this simple chain
    bool chainOk =
        targetNotified &&
        observer1Notified &&
        observer2Notified &&
        target->getCallCount() == 1 &&
        observer1->getCallCount() == 1 &&
        observer2->getCallCount() == 1;

    // 7. Return total call count and chain status
    return {totalCallCount, chainOk};
}

