                                               int batchA,
                                               int batchB) {
  using namespace reaction;

  // 1. Create reactive variables
  auto a = var(initialA);
  auto b = var(initialB);

  // 2. Create variable to track recomputation count
  int recomputeCount = 0;

  // 3. Create calculation (derived value) that tracks recomputations
  auto sum = calc([&]() {
    ++recomputeCount;
    return a.get() + b.get();
  });

  // Force initial evaluation so recomputeCount starts from 1
  (void)sum.get();

  // 4. Perform non-batch updates (each should trigger recomputation)
  a.value(nonBatchA);
  b.value(nonBatchB);

  // Ensure derived value is evaluated after non-batch updates
  (void)sum.get();

  // 5. Record recompute count after non-batch updates
  int countAfterNonBatch = recomputeCount;

  // 6. Create batch context and 7. Execute batch updates within it
  {
    auto batchCtx = batch();
    (void)batchCtx;  // avoid unused warning if batch() returns RAII object

    a.value(batchA);
    b.value(batchB);

    // Re-evaluate inside batch context if the framework defers execution
    (void)sum.get();
  }

  // 8. Record recompute count after batch updates
  int countAfterBatch = recomputeCount;

  // 9. Return final sum and counts
  return std::make_tuple(sum.get(), countAfterNonBatch, countAfterBatch);
}

