#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

// ============================================
// Helper types
// ============================================

class RecordingNode : public reaction::ObserverNode {
public:
    void valueChanged(bool changed = true) override {
        if (changed) {
            ++m_notifications;
        }
        // propagate to downstream observers as usual
        this->notify(changed);
    }

    int notificationCount() const {
        return m_notifications;
    }

private:
    int m_notifications = 0;
};

struct RollbackObservation {
    int notificationsAfterSecondBinding;
    int notificationsAfterRollback;
};

// ============================================
// Function implementation
// ============================================

inline RollbackObservation test_observer_state_rollback() {
    using reaction::ObserverGraph;
    using reaction::ObserverNode;

    auto &graph = ObserverGraph::getInstance();

    // 1. Create RecordingNode instances
    auto source1 = std::make_shared<RecordingNode>();
    auto source2 = std::make_shared<RecordingNode>();
    auto observer = std::make_shared<RecordingNode>();

    // 2. Graph instance acquired above
    // 3. Register nodes in the graph
    graph.registerNode(source1);
    graph.registerNode(source2);
    graph.registerNode(observer);

    // 4. Set up initial dependency: observer depends on source1
    graph.addObserver(source1, observer);

    // 5. Save node state for rollback
    auto token = graph.saveState();

    // 6. Replace dependencies transactionally: move observer from source1 to source2
    graph.beginTransaction();
    graph.removeObserver(source1, observer);
    graph.addObserver(source2, observer);
    graph.commitTransaction();

    // 7. Trigger notification on second sensor (source2)
    source2->valueChanged(true);

    // 8. Record notification count after second binding
    RollbackObservation result{};
    result.notificationsAfterSecondBinding = observer->notificationCount();

    // 9. Execute rollback
    graph.rollback(token);

    // 10. Trigger notification on first sensor (source1)
    source1->valueChanged(true);

    // 11. Record notification count after rollback
    result.notificationsAfterRollback = observer->notificationCount();

    // 12. Return notification counts
    return result;
}

}  // namespace test_reaction

