#pragma once

#include <reaction/reaction.h>
#include <string>
#include <unordered_set>

namespace test_reaction {

class NamedObserverNode : public reaction::ObserverNode {
public:
    explicit NamedObserverNode(std::string name)
        : m_name(std::move(name)) {}

    const std::string& name() const {
        return m_name;
    }

private:
    std::string m_name;
};

struct ObserverCollectionSummary {
    std::size_t totalObservers;
    bool containsDirectObserver;
    bool containsTransitiveObserver;
};

ObserverCollectionSummary test_observer_collection() {
    using reaction::ObserverGraph;
    using reaction::ObserverNode;

    // 1. Create NamedObserverNode instances
    auto subject = std::make_shared<NamedObserverNode>("subject");
    auto directObserver = std::make_shared<NamedObserverNode>("direct");
    auto transitiveObserver = std::make_shared<NamedObserverNode>("transitive");

    // 2. Get observer graph instance
    auto& graph = ObserverGraph::getInstance();

    // 3. Register nodes
    graph.registerNode(subject);
    graph.registerNode(directObserver);
    graph.registerNode(transitiveObserver);

    // 4. Set up direct observer relationship: subject -> directObserver
    subject->addOneObserver(directObserver);

    // 5. Set up transitive observer relationship: directObserver -> transitiveObserver
    directObserver->addOneObserver(transitiveObserver);

    // 6. Create NodeSet to store collected observers
    using NodePtr = std::shared_ptr<ObserverNode>;
    using NodeSet = std::unordered_set<NodePtr>;
    NodeSet collected;

    // 7. Collect observers (transitively)
    graph.collectObservers(subject, collected);

    // 8. Check if direct observer is in collected set
    bool containsDirect = collected.find(directObserver) != collected.end();

    // 9. Check if transitive observer is in collected set
    bool containsTransitive = collected.find(transitiveObserver) != collected.end();

    // 10. Return collection summary
    ObserverCollectionSummary summary{
        collected.size(),
        containsDirect,
        containsTransitive
    };
    return summary;
}

}  // namespace test_reaction
