```cpp
#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

struct BatchExecuteResult {
    int recomputeCountBeforeBatch;
    int recomputeCountAfterBatch;
    int finalValue;
};

inline BatchExecuteResult test_batch_execute_update(int baseValue, int deltaA, int deltaB) {
    using namespace reaction;

    // 1. Create reactive variable
    auto a = make_var(baseValue);

    // 2. Create variable to track recomputation count
    int recomputeCount = 0;

    // 3. Create calculation
    //    Simple calculation that depends on `a` and increments the recompute counter
    auto calc = make_calc([&]() {
        ++recomputeCount;
        return a.get() * 2;
    });

    // Force initial computation so recomputeCount reflects that
    (void)calc.get();

    // 4. Record recompute count before batch
    int recomputeCountBeforeBatch = recomputeCount;

    // 5. Execute batch updates
    {
        ScopedBatch batch;  // Enables batched execution (g_batch_execute = true)
        a.set(a.get() + deltaA);
        a.set(a.get() + deltaB);
        // No intermediate recomputation should happen until batch ends
    }

    // 6. Record recompute count after batch
    int recomputeCountAfterBatch = recomputeCount;

    // 7. Get final value
    int finalValue = calc.get();

    // 8. Return batch execution result
    return BatchExecuteResult{
        recomputeCountBeforeBatch,
        recomputeCountAfterBatch,
        finalValue
    };
}

}  // namespace test_reaction
