```cpp
#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

struct BatchLifecycleResult {
    bool closedInitially;
    bool closedAfterClose;
    int recomputeCountAfterExecute;
};

inline BatchLifecycleResult test_batch_manual_lifecycle(int initialValue, int updatedValue) {
    using namespace reaction;

    // 1. Create reactive variable
    auto v = var(initialValue);

    // 2. Create variable to track recomputation count
    int recomputeCount = 0;

    // 3. Create calculation
    auto c = calc([&](auto value) {
        ++recomputeCount;
        return value;
    }, v);

    // Force initial evaluation so later changes are observable
    (void)c.get();

    // 4. Create Batch object (manual lifecycle, not RAII)
    Batch batch;

    // 5. Check if batch is closed initially
    bool closedInitially = batch.closed();

    // 6. Execute batch
    // For manual lifecycle, we assume:
    //  - creating the Batch put us in batching mode
    //  - execute() will flush batched recomputations without closing it
    v.set(updatedValue);
    batch.execute();

    // 7. Record recompute count after execute
    int recomputeCountAfterExecute = recomputeCount;

    // 8. Close batch
    batch.close();

    // 9. Check if batch is closed after close
    bool closedAfterClose = batch.closed();

    // 10. Ensure calculation is evaluated (and reflects latest value)
    (void)c.get();

    // 11. Return batch lifecycle result
    return BatchLifecycleResult{
        closedInitially,
        closedAfterClose,
        recomputeCountAfterExecute
    };
}

}  // namespace test_reaction
