#pragma once

#include <array>
#include <cstddef>
#include <reaction/memory/sbo_resource.h>

namespace test_reaction {

using namespace reaction::memory;

struct SmallPayload {
    int value;
    bool operator!=(const SmallPayload& other) const = default;
};

struct LargePayload {
    std::array<int, 64> data{};
    bool operator!=(const LargePayload& other) const = default;
};

struct SboStorageStatus {
    bool updateReportedChange;
    bool smallUsingSBO;
    std::size_t smallStackUsage;
    bool largeInitialized;
    bool largeUsingSBO;
};

inline SboStorageStatus test_sbo_storage_info(int initialSmall,
                                              int updatedSmall,
                                              int largeSeed) {
    // 1. Lambda to make a large payload from a seed
    auto makeLargePayload = [](int seed) {
        LargePayload lp;
        for (std::size_t i = 0; i < lp.data.size(); ++i) {
            lp.data[i] = seed + static_cast<int>(i);
        }
        return lp;
    };

    // 2. Create small SBOResource
    SBOResource<SmallPayload> smallResource(SmallPayload{initialSmall});

    // 3. Create large SBOResource
    LargePayload initialLarge = makeLargePayload(largeSeed);
    SBOResource<LargePayload> largeResource(initialLarge);

    // 4. Update small resource value
    bool updateReportedChange =
        smallResource.updateValue(SmallPayload{updatedSmall});

    // 5. Get storage information for small resource
    bool smallUsingSBO = smallResource.isUsingSBO();
    std::size_t smallStackUsage = smallResource.getStackUsage();

    // 6. Get storage information for large resource
    bool largeUsingSBO = largeResource.isUsingSBO();
    bool largeInitialized =
        (largeResource.getValue() != LargePayload{});  // non-default?

    // 7. Return SBO storage status
    return SboStorageStatus{
        updateReportedChange,
        smallUsingSBO,
        smallStackUsage,
        largeInitialized,
        largeUsingSBO,
    };
}

}  // namespace test_reaction
