#pragma once

#include <reaction/concurrency/thread_manager.h>

namespace test_reaction {

struct ConditionalMutexResult {
    bool tryLockWithoutSafety;
    bool tryLockWithSafety;
};

inline ConditionalMutexResult test_conditional_mutex_behavior() {
    using namespace reaction;

    // 1. Get thread manager instance
    auto& tm = ThreadManager::instance();

    // 2. Reset thread manager state
    tm.reset_state();

    // 3. Create ConditionalMutex instance
    ConditionalMutex mutex;

    ConditionalMutexResult result{};

    // 4. Create ConditionalLockGuard in a scope block
    {
        ConditionalLockGuard guard(mutex);

        // 5. Attempt to lock mutex without safety enabled
        //    Thread safety is not yet enabled, so the mutex should behave as a no-op
        //    and try_lock should effectively succeed.
        result.tryLockWithoutSafety = mutex.try_lock();
    } // 6. Exit guard scope

    // 7. Enable thread safety
    tm.enable_thread_safety(true);

    // 8. Create ConditionalLockGuard in a scope block again
    {
        ConditionalLockGuard guard(mutex);

        // 9. Attempt to lock mutex with safety enabled
        //    Now the mutex is active. Since `guard` already holds the lock,
        //    this secondary try_lock should fail if the mutex is working.
        result.tryLockWithSafety = mutex.try_lock();
    } // 10. Exit guard scope

    // 11. Return conditional mutex result
    return result;
}

}  // namespace test_reaction
