```cpp
#pragma once

#include <reaction/reaction.h>
#include <set>
#include <string>
#include <vector>

namespace test_reaction {

struct OrderingSnapshot {
    std::vector<std::string> orderedNames;
    bool allUnique;
};

/**
 * Function: Demonstrate React::operator< for ordering reactive handles.
 *
 * @param firstName Name assigned to the first reactive node
 * @param secondName Name assigned to the second reactive node
 * @param thirdName Name assigned to the third reactive node
 * @return OrderingSnapshot Snapshot of sorted names and uniqueness flag
 */
inline OrderingSnapshot test_react_ordering(const std::string &firstName,
                                            const std::string &secondName,
                                            const std::string &thirdName) {
    using reaction::React;
    using reaction::field;

    // 1. Create three reactive variables (fields) with initial string values
    React<std::string> first  = field(firstName);
    React<std::string> second = field(secondName);
    React<std::string> third  = field(thirdName);

    // 2. Insert them into a std::set to use React::operator< for ordering
    std::set<React<std::string>> reactSet;
    reactSet.insert(first);
    reactSet.insert(second);
    reactSet.insert(third);

    // 3. Collect ordered names based on the set ordering of the reactive handles
    OrderingSnapshot snapshot;
    snapshot.orderedNames.reserve(reactSet.size());
    for (const auto &reactVar : reactSet) {
        snapshot.orderedNames.push_back(reactVar.get());
    }

    // 4. Check if all names are unique
    std::set<std::string> uniqueNames(snapshot.orderedNames.begin(),
                                      snapshot.orderedNames.end());
    snapshot.allUnique = (uniqueNames.size() == snapshot.orderedNames.size());

    // 5. Return the ordering snapshot
    return snapshot;
}

}  // namespace test_reaction
