```cpp
#pragma once

#include <reaction/core/observer_node.h>
#include <reaction/graph/observer_graph.h>
#include <memory>
#include <string>

namespace test_reaction {

class ResetAwareNode : public reaction::ObserverNode {
public:
    explicit ResetAwareNode(std::string name)
        : m_name(std::move(name)), m_notifications(0) {}

    // Count how many times this node was notified
    int notifications() const {
        return m_notifications;
    }

    // Clear notification count
    void clear() {
        m_notifications = 0;
    }

    // Override notify to track notifications
    void notify(bool changed) override {
        // Count only "changed" notifications, which is the usual behavior
        if (changed) {
            ++m_notifications;
        }
        // Preserve base behavior (propagate downstream)
        ObserverNode::notify(changed);
    }

    // Provide a reset hook so tests can explicitly reset this node
    void reset() override {
        // Let the base class do its reset behavior (graph-related cleanup)
        ObserverNode::reset();
        // Also reset our own tracking state
        m_notifications = 0;
    }

private:
    std::string m_name;
    int m_notifications;
};

struct ResetNodeResult {
    bool notifiedBeforeReset;
    bool notifiedAfterReset;
};

inline ResetNodeResult test_graph_reset_node(const std::string &sourceName,
                                             const std::string &targetName) {
    using reaction::ObserverGraph;
    using reaction::ObserverNode;

    // 1. Create source and target ResetAwareNode instances
    auto source = std::make_shared<ResetAwareNode>(sourceName);
    auto target = std::make_shared<ResetAwareNode>(targetName);

    // 2. Get observer graph instance
    auto &graph = ObserverGraph::getInstance();

    // 3. Register nodes
    graph.registerNode(source);
    graph.registerNode(target);

    // 4. Set up observer relationship: source -> target
    graph.addObserver(source, target);

    // 5. Trigger notification on source
    source->valueChanged(true);

    // 6. Check if target was notified before reset
    bool notifiedBeforeReset = (target->notifications() > 0);

    // 7. Clear target notification count
    target->clear();

    // 8. Reset target node (clear internal state and detach from graph)
    graph.resetNode(target);

    // 9. Trigger notification on source again
    source->valueChanged(true);

    // 10. Check if target was notified after reset
    bool notifiedAfterReset = (target->notifications() > 0);

    // 11. Close nodes (unregister from graph / clean up)
    graph.closeNode(source);
    graph.closeNode(target);

    // 12. Return reset node result
    return ResetNodeResult{notifiedBeforeReset, notifiedAfterReset};
}

}  // namespace test_reaction
