  EXPECT_TRUE(snapshot.guardSucceeded);
  EXPECT_TRUE(snapshot.allocationBlockedAtLimit);
  EXPECT_TRUE(snapshot.runtimeAllowedAfterRelease);
}

}  // namespace test_reaction

