#pragma once

#include <reaction/memory/memory_config.h>
#include <reaction/memory/stack_monitor.h>

namespace test_reaction {

struct StackAllocationSnapshot {
    bool smallAllowedWithoutMonitoring;
    bool largeAllowedWithoutMonitoring;
    bool runtimeAllowedWithoutMonitoring;
    bool largeAllowedWithMonitoring;
    bool guardSucceeded;
    bool allocationBlockedAtLimit;
    bool runtimeAllowedAfterRelease;
};

/**
 * Function: Demonstrate StackMonitor::canAllocate behaviour across modes.
 *
 * @param largeSize Value used for runtime canAllocate after release
 * @return StackAllocationSnapshot Snapshot of allocation checks before/after guard
 */
inline StackAllocationSnapshot test_stack_monitor_capacity(std::size_t largeSize) {
    using reaction::memory::StackMonitor;
    using reaction::memory::MemoryConfig;

    StackAllocationSnapshot snapshot{};

    // 1. Disable monitoring (simulated by not calling initialize yet)
    // 2. Initialize stack monitor (this sets usage to 0 and enables monitoring,
    //    but we first capture behaviour before initialize by directly querying
    //    canAllocate without any guard/usage)
    // Check "without monitoring" as meaning "no active StackGuard / zero usage"
    constexpr std::size_t smallSize = MemoryConfig::SBO_STACK_LIMIT / 4;
    constexpr std::size_t largeLimitSize = MemoryConfig::SBO_STACK_LIMIT;

    // 3. Check allocation without monitoring: we call canAllocate before initialize
    snapshot.smallAllowedWithoutMonitoring = StackMonitor::canAllocate(smallSize);
    snapshot.largeAllowedWithoutMonitoring = StackMonitor::canAllocate(largeLimitSize);
    snapshot.runtimeAllowedWithoutMonitoring = StackMonitor::canAllocate(largeSize);

    // Now actually initialize monitoring for the rest of the test
    StackMonitor::initialize();

    // 4. Enable monitoring (already done by initialize)

    // 5. Initialize stack monitor again (re-initialize to reset usage)
    StackMonitor::initialize();

    // 6. Check large allocation with monitoring (no guard yet, usage is 0)
    snapshot.largeAllowedWithMonitoring = StackMonitor::canAllocate(largeLimitSize);

    // 7. Create StackGuard in scope block
    {
        reaction::memory::StackGuard guard(largeLimitSize);

        // 8. Check if guard succeeded
        snapshot.guardSucceeded = guard.succeeded();

        // 9. Check if allocation blocked at limit
        // A further allocation of any positive size should be blocked if the guard succeeded
        snapshot.allocationBlockedAtLimit =
            snapshot.guardSucceeded && !StackMonitor::canAllocate(1);
        // Guard goes out of scope here
    }

    // 10. Exit guard scope (done by block end)

    // 11. Check runtime allocation after release
    snapshot.runtimeAllowedAfterRelease = StackMonitor::canAllocate(largeSize);

    // 12. Return stack allocation snapshot
    return snapshot;
}

}  // namespace test_reaction
