#pragma once

#include <reaction/memory/memory_config.h>
#include <reaction/memory/stack_monitor.h>

namespace test_reaction {

struct StackLimitSnapshot {
    reaction::memory::StackMonitor::UsageStats statsBeforeGuard;
    reaction::memory::StackMonitor::UsageStats statsAfterGuard;
    bool templateAllocationAllowed;
    bool runtimeAllocationAllowed;
    bool guardHeld;
    bool allocationBlockedWhileGuardHeld;
};

inline StackLimitSnapshot test_stack_monitor_limits() {
    using reaction::memory::StackMonitor;

    StackLimitSnapshot snapshot{};

    // 1. Enable monitoring
    StackMonitor::enableMonitoring();

    // 2. Initialize stack monitor (reset usage)
    StackMonitor::resetUsage();

    // 3. Get usage statistics before guard
    snapshot.statsBeforeGuard = StackMonitor::getUsageStats();

    // 4. Check if template allocation is allowed
    // Use a 64-byte template size as a representative small allocation
    snapshot.templateAllocationAllowed =
        StackMonitor::canAllocateTemplate<64>();

    // 5. Check if runtime allocation is allowed
    // Use a 64-byte runtime allocation as well
    snapshot.runtimeAllocationAllowed =
        StackMonitor::canAllocateRuntime(64);

    // 6. Create large StackGuard instance
    // Choose a size larger than any reasonable threshold to force limit behavior
    constexpr std::size_t GuardSize = 1 << 20;  // 1 MiB
    bool guardSucceeded = false;
    bool allocationBlockedWithGuard = false;

    {
        auto guard = StackMonitor::makeGuard<GuardSize>();
        guardSucceeded = guard.isHeld();
        snapshot.guardHeld = guardSucceeded;

        // 8. Check if allocation blocked while guard is held
        // Try another large allocation; it should typically be blocked
        allocationBlockedWithGuard =
            !StackMonitor::canAllocateRuntime(GuardSize);
        snapshot.allocationBlockedWhileGuardHeld = allocationBlockedWithGuard;

        // guard goes out of scope at end of block
    }

    // If guard was not actually held, we can't rely on the "blocked" result
    if (!guardSucceeded) {
        snapshot.allocationBlockedWhileGuardHeld = false;
    }

    // 9. Get usage statistics after guard
    snapshot.statsAfterGuard = StackMonitor::getUsageStats();

    // 10. Return stack limit snapshot
    return snapshot;
}

}  // namespace test_reaction

