        auto guard = StackMonitor::makeGuard<GuardSize>();
        guardSucceeded = guard.isHeld();
        snapshot.guardHeld = guardSucceeded;

        // 8. Check if allocation blocked while guard is held
        // Try another large allocation; it should typically be blocked
        allocationBlockedWithGuard =
            !StackMonitor::canAllocateRuntime(GuardSize);
        snapshot.allocationBlockedWhileGuardHeld = allocationBlockedWithGuard;

        // guard goes out of scope at end of block
    }

    // If guard was not actually held, we can't rely on the "blocked" result
    if (!guardSucceeded) {
        snapshot.allocationBlockedWhileGuardHeld = false;
    }

    // 9. Get usage statistics after guard
    snapshot.statsAfterGuard = StackMonitor::getUsageStats();

    // 10. Return stack limit snapshot
    return snapshot;
}

}  // namespace test_reaction

