    snapshot.afterBitwiseAnd = calc.get();

    // 10. Apply atomic left shift
    counter.fetch_lshift(1);

    // 11. Get value after shift
    snapshot.afterShift = calc.get();

    // 12. Apply post-increment
    snapshot.postIncrementReturn = counter++;

    // 13. Get final value
    snapshot.finalValue = calc.get();

    // 14. Return atomic compound snapshot
    snapshot.calcEvaluations = evalCount;
    return snapshot;
}

